module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const showScale = !(args.showscale === false || args.showscale === 'false');
const rowH = (() => { const n = parseFloat(args.rowheight); return Number.isFinite(n) && n > 0 ? n : 26; })();
const sort = (args.sort || 'none').toLowerCase();
const fillOp = (() => { const n = parseFloat(args.fillopacity); return Number.isFinite(n) ? Math.max(0, Math.min(100, n)) : 22; })();
const series = [];
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const i = s.indexOf('|');
  const label = i >= 0 ? s.slice(0, i).trim() : '';
  const nums = (i >= 0 ? s.slice(i + 1) : s).trim().split(/\s+/).map(parseFloat).filter((x) => Number.isFinite(x));
  if (nums.length >= 5) series.push({ label, v: nums.slice(0, 5).sort((a, b) => a - b) });
});
if (!series.length) return `<div>(boxplot: "label | min q1 median q3 max" per section)</div>`;
if (sort === 'asc') series.sort((a, b) => a.v[2] - b.v[2]);
else if (sort === 'desc') series.sort((a, b) => b.v[2] - a.v[2]);
const all = series.flatMap((s) => s.v);
let lo = args.min !== '' && args.min != null ? parseFloat(args.min) : Math.min(...all);
let hi = args.max !== '' && args.max != null ? parseFloat(args.max) : Math.max(...all);
if (!Number.isFinite(lo)) lo = 0; if (!Number.isFinite(hi)) hi = 1; if (hi === lo) hi = lo + 1;
const pct = (v) => ((v - lo) / (hi - lo)) * 100;
let rows = '';
series.forEach((s) => {
  const [mn, q1, med, q3, mx] = s.v;
  rows += `<div class="mdp-bp-row"><div class="mdp-bp-label">${esc(s.label)}</div><div class="mdp-bp-track">` +
    `<div class="mdp-bp-whisker" style="left:${pct(mn).toFixed(2)}%; width:${(pct(mx) - pct(mn)).toFixed(2)}%;"></div>` +
    `<div class="mdp-bp-cap" style="left:${pct(mn).toFixed(2)}%;"></div>` +
    `<div class="mdp-bp-cap" style="left:${pct(mx).toFixed(2)}%;"></div>` +
    `<div class="mdp-bp-box" style="left:${pct(q1).toFixed(2)}%; width:${(pct(q3) - pct(q1)).toFixed(2)}%;"></div>` +
    `<div class="mdp-bp-median" style="left:${pct(med).toFixed(2)}%;"></div>` +
    `</div></div>`;
});
const scale = showScale ? `<div class="mdp-bp-scale"><span>${(+lo.toFixed(4))}</span><span>${(+hi.toFixed(4))}</span></div>` : '';
return `\n\n<div class="mdp-mod-boxplot" style="--bp-c:${color}; --bp-h:${rowH}px; --bp-fill:${fillOp}%;">${rows}${scale}</div>\n\n`;
